// @vitest-environment node
/**
 * SPEC-037: supresión robusta de preguntas casi idénticas en el asistente —
 * similitud aproximada (tokens significativos sin stopwords/diacríticos,
 * equivalencia por prefijo común ≥ 5, solapamiento ≥ 0.7) contra TODA la cola
 * (pendientes + ancladas), primera barrera reforzada en el prompt (no
 * reformulaciones + repetir texto exacto) y regresión de invariantes de
 * SPEC-021/023/036 (systemBlocks byte-estables, orden similitud→capacidad,
 * encolado al frente con id y suggestionCount solo de aceptadas).
 * Generated by QA Dev agent.
 *
 * Arnés de SPEC-016/021/036 (SDK y Deepgram mockeados con clases de error
 * espejo, store/repository y transcriptionService REALES, fake timers solo de
 * Date).
 */
import { mkdtempSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import type { WebContents } from 'electron'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import {
  MIN_INTERVAL_MS,
  setAssistantPinned,
  startAssistant,
  stopAssistant
} from '../../../src/main/assistantService'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import type { DeepgramCallbacks } from '../../../src/main/deepgramService'
import { resetTranscription, startTranscription } from '../../../src/main/transcriptionService'
import type {
  AssistantQueue,
  AssistantUpdateEvent
} from '../../../src/renderer/src/types/assistant'

const harness = vi.hoisted(() => {
  /** Jerarquía espejo de la del SDK: instanceof debe funcionar en mapSdkError. */
  class APIError extends Error {}
  class AuthenticationError extends APIError {}
  class RateLimitError extends APIError {}
  class APIConnectionError extends APIError {}
  return {
    create: vi.fn(),
    dgInstances: [] as unknown[],
    errors: { APIError, AuthenticationError, RateLimitError, APIConnectionError }
  }
})

vi.mock('@anthropic-ai/sdk', () => {
  class MockAnthropic {
    static APIError = harness.errors.APIError
    static AuthenticationError = harness.errors.AuthenticationError
    static RateLimitError = harness.errors.RateLimitError
    static APIConnectionError = harness.errors.APIConnectionError
    readonly messages = { create: harness.create }
  }
  return { default: MockAnthropic }
})

vi.mock('../../../src/main/deepgramService', () => ({
  DeepgramConnection: class {
    apiKey: string
    callbacks: DeepgramCallbacks
    opened = false
    isOpen = false
    sendAudio = vi.fn(() => true)
    sendKeepAlive = vi.fn()
    closeStream = vi.fn()
    terminate = vi.fn()

    constructor(apiKey: string, callbacks: DeepgramCallbacks) {
      this.apiKey = apiKey
      this.callbacks = callbacks
      harness.dgInstances.push(this)
    }
  },
  classifyConnectionFailure: vi.fn(() => Promise.resolve('other' as const))
}))

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  },
  safeStorage: {
    isEncryptionAvailable: (): boolean => true,
    encryptString: (plain: string): Buffer => Buffer.from(plain, 'utf8'),
    decryptString: (blob: Buffer): string => blob.toString('utf8')
  }
}))

interface FakeConnection {
  callbacks: DeepgramCallbacks
  opened: boolean
  isOpen: boolean
}

/** Parámetros relevantes de una llamada create del asistente. */
interface CreateParams {
  system: unknown
  messages: Array<{ role: string; content: string }>
}

function createCall(index: number): CreateParams {
  return harness.create.mock.calls[index][0] as CreateParams
}

/** Respuesta del SDK con bloque thinking + bloque text (el JSON va en text). */
function sdkResponse(payload: Record<string, unknown>): unknown {
  return {
    stop_reason: 'end_turn',
    content: [
      { type: 'thinking', thinking: 'razonamiento' },
      { type: 'text', text: JSON.stringify(payload) }
    ]
  }
}

function analysisPayload(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    action: 'continue',
    suggestedQuestion: '¿Cuándo fue la última vez que pasó?',
    reason: 'Ya hay material concreto para avanzar',
    alarms: [],
    objectivesMet: [],
    resolvedQueueIndexes: [],
    ...overrides
  }
}

function createSender(): { sender: WebContents; send: ReturnType<typeof vi.fn> } {
  const send = vi.fn()
  const senderLike = {
    isDestroyed: (): boolean => false,
    send
  }
  return { sender: senderLike as unknown as WebContents, send }
}

function assistantEvents(send: ReturnType<typeof vi.fn>): AssistantUpdateEvent[] {
  return send.mock.calls
    .filter((call) => call[0] === 'assistant:update')
    .map((call) => call[1] as AssistantUpdateEvent)
}

const BASE_TIME_MS = 1_000_000_000

let send: ReturnType<typeof vi.fn>
let connection: FakeConnection
let lineCounter = 0
let analysisCount = 0

/** Inyecta una línea final por la vía pública (transcripción real mockeada). */
function feedFinal(): void {
  lineCounter += 1
  connection.callbacks.onResult({
    channelIndex: lineCounter % 2,
    transcript: `Línea de conversación ${lineCounter}`,
    isFinal: true,
    startSeconds: lineCounter,
    durationSeconds: 1,
    speaker: 0
  })
}

/** Último estado de la cola emitido por main (fuente de verdad del renderer). */
function lastQueue(): AssistantQueue {
  const queue = assistantEvents(send).at(-1)?.queue
  if (queue === undefined) {
    throw new Error('sin eventos del asistente todavía')
  }
  return queue
}

function pendingQuestions(): string[] {
  return lastQueue().pending.map((item) => item.suggestedQuestion)
}

/** Arranca transcripción + asistente sobre una entrevista con objetivos y guión. */
function startSession(): void {
  const discovery = repository.createDiscovery({ name: 'Discovery Maurya' })
  const interview = repository.createInterview({
    discoveryId: discovery.id,
    title: 'Entrevista con similitud'
  })
  repository.updateInterview(interview.id, {
    objectives: ['Objetivo cero', 'Objetivo uno'],
    scriptMarkdown: '# Guión de la entrevista'
  })

  const transcriptionSender = createSender()
  startTranscription(transcriptionSender.sender)
  connection = harness.dgInstances[0] as FakeConnection
  connection.opened = true
  connection.isOpen = true
  connection.callbacks.onOpen()

  const assistantSender = createSender()
  send = assistantSender.send
  startAssistant(assistantSender.sender, interview.id)
}

/**
 * Ejecuta UN análisis completo: avanza la ventana de 20 s si no es el
 * primero, inyecta 3 líneas finales y espera analyzing→active (cada análisis
 * exitoso añade exactamente 2 eventos, con o sin candidata aceptada).
 */
async function analyze(overrides: Record<string, unknown> = {}): Promise<void> {
  analysisCount += 1
  const expectedCalls = analysisCount
  const eventsBefore = assistantEvents(send).length
  harness.create.mockResolvedValueOnce(sdkResponse(analysisPayload(overrides)))
  if (expectedCalls > 1) {
    vi.setSystemTime(BASE_TIME_MS + (expectedCalls - 1) * (MIN_INTERVAL_MS + 1000))
  }
  feedFinal()
  feedFinal()
  feedFinal()
  await vi.waitFor(() => expect(harness.create).toHaveBeenCalledTimes(expectedCalls))
  await vi.waitFor(() => {
    const events = assistantEvents(send)
    expect(events.length).toBeGreaterThanOrEqual(eventsBefore + 2)
    expect(events.at(-1)?.state).toBe('active')
  })
}

/** Texto plano del prompt de sistema (todos los bloques concatenados). */
function systemText(index: number): string {
  const blocks = createCall(index).system as Array<{ text: string }>
  return blocks.map((block) => block.text).join('\n')
}

beforeEach(() => {
  vi.clearAllMocks()
  harness.dgInstances.length = 0
  lineCounter = 0
  analysisCount = 0
  vi.useFakeTimers({ toFake: ['Date'] })
  vi.setSystemTime(BASE_TIME_MS)
  initStore(mkdtempSync(join(tmpdir(), 'maurya-assistant-similarity-')))
  process.env['ANTHROPIC_API_KEY'] = 'sk-ant-test'
  process.env['DEEPGRAM_API_KEY'] = 'dg-test'
})

afterEach(() => {
  stopAssistant()
  resetTranscription()
  vi.useRealTimers()
  delete process.env['ANTHROPIC_API_KEY']
  delete process.env['DEEPGRAM_API_KEY']
})

describe('assistantService (similitud SPEC-037)', () => {
  describe('deterministic near-duplicate suppression', () => {
    // SPEC-037 · AC-01 (reformulación del mismo tema → descartada, cola intacta)
    it('discards a rephrased near-duplicate of a pending question keeping the queue unchanged', async () => {
      startSession()
      await analyze({
        suggestedQuestion: '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      })
      await analyze({
        suggestedQuestion: '¿Cuánto pagasteis por esa herramienta que comprasteis la última vez?'
      })

      expect(pendingQuestions()).toEqual([
        '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      ])
    })

    // SPEC-037 · AC-02 (solo mayúsculas/diacríticos/puntuación → descartada)
    it('discards a candidate that only differs in case, diacritics or punctuation', async () => {
      startSession()
      await analyze({
        suggestedQuestion: '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      })
      await analyze({
        suggestedQuestion: '¿CUANTO pagasteis por la ultima herramienta que comprasteis!'
      })

      expect(pendingQuestions()).toEqual([
        '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      ])
    })

    // SPEC-037 · AC-03 (la barrera cubre también las ANCLADAS)
    it('discards a near-duplicate of a pinned question keeping pending and pinned unchanged', async () => {
      startSession()
      await analyze({
        suggestedQuestion: '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      })
      setAssistantPinned(lastQueue().pending[0].id, true)

      await analyze({
        suggestedQuestion: '¿Cuánto pagasteis por esa herramienta que comprasteis la última vez?'
      })

      expect(pendingQuestions()).toEqual([])
      expect(lastQueue().pinned.map((item) => item.suggestedQuestion)).toEqual([
        '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      ])
    })

    // SPEC-037 · AC-04 (variación singular/plural y de sufijos: gestionar≡gestión)
    it('discards a same-topic candidate with singular/plural and suffix variations', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Cuánto pagáis hoy por gestionar las citas?' })
      await analyze({
        suggestedQuestion: '¿Cuánto pagáis actualmente por la gestión de las citas?'
      })

      expect(pendingQuestions()).toEqual(['¿Cuánto pagáis hoy por gestionar las citas?'])
    })

    // SPEC-037 · AC-05 (la suprimida no cuenta y el evento lleva la cola sin ella)
    it('keeps suggestionCount untouched and emits the queue without the suppressed candidate', async () => {
      startSession()
      await analyze({
        suggestedQuestion: '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      })
      await analyze({
        suggestedQuestion: '¿Cuánto pagasteis por esa herramienta que comprasteis la última vez?'
      })

      const lastEvent = assistantEvents(send).at(-1)
      expect(lastEvent?.state).toBe('active')
      expect(lastEvent?.queue.pending.map((item) => item.suggestedQuestion)).toEqual([
        '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      ])
      expect(stopAssistant()?.suggestionCount).toBe(1)
    })
  })

  describe('distinct candidate acceptance', () => {
    // SPEC-037 · AC-06 (tema distinto → entra al frente de pendientes)
    it('enqueues a distinct-topic candidate at the front of the pending queue', async () => {
      startSession()
      await analyze({
        suggestedQuestion: '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      })
      await analyze({ suggestedQuestion: '¿Quién decidió esa compra dentro del equipo?' })

      expect(pendingQuestions()).toEqual([
        '¿Quién decidió esa compra dentro del equipo?',
        '¿Cuánto pagasteis por la última herramienta que comprasteis?'
      ])
    })

    // SPEC-037 · AC-07 (comparte alguna palabra pero el tema es otro → entra)
    it('enqueues a candidate that shares a word with a queued question but targets another topic', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Qué herramienta usáis para las citas?' })
      await analyze({
        suggestedQuestion: '¿Cuánto tiempo perdisteis la última semana por culpa de los no-shows?'
      })

      expect(pendingQuestions()).toEqual([
        '¿Cuánto tiempo perdisteis la última semana por culpa de los no-shows?',
        '¿Qué herramienta usáis para las citas?'
      ])
    })

    // SPEC-037 · AC-08 (contra cola vacía nunca se descarta)
    it('always enqueues the candidate when the queue is empty', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Cuándo fue la última vez que pasó?' })

      expect(pendingQuestions()).toEqual(['¿Cuándo fue la última vez que pasó?'])
    })
  })

  describe('prompt first barrier', () => {
    // SPEC-037 · AC-09 (instrucción: tampoco reformulaciones del mismo tema)
    it('instructs the model not to propose rephrasings of the same topic as queued questions', async () => {
      startSession()
      await analyze()

      expect(systemText(0)).toContain(
        'NO propongas una pregunta igual, casi igual ni una reformulación del mismo tema con otras palabras'
      )
    })

    // SPEC-037 · AC-10 (instrucción: repetir EXACTAMENTE el texto de la cola)
    it('instructs the model to repeat the exact queued text when the best next question is already queued', async () => {
      startSession()
      await analyze()

      expect(systemText(0)).toContain(
        'Si la mejor siguiente pregunta ya está en la cola, repite EXACTAMENTE el mismo texto'
      )
    })
  })

  describe('regression (SPEC-021/023/036 invariants)', () => {
    // SPEC-037 · AC-11 (prefijo cacheado byte-idéntico entre llamadas)
    it('keeps the system blocks byte-identical across analyses after the similarity change', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta uno sobre herramientas?' })
      await analyze({ suggestedQuestion: '¿Pregunta dos sobre presupuesto anual?' })
      await analyze({ suggestedQuestion: '¿Pregunta tres sobre decisiones internas?' })

      expect(JSON.stringify(createCall(1).system)).toBe(JSON.stringify(createCall(0).system))
      expect(JSON.stringify(createCall(2).system)).toBe(JSON.stringify(createCall(0).system))
    })

    // SPEC-037 · AC-12 (gate de capacidad intacto para candidatas NO similares)
    // Revisado por la revisión de coste 2026-07: con las pendientes al máximo
    // los disparos por líneas SE SALTAN (degradación de frecuencia) — el gate
    // actúa ya en el disparador y la cola queda intacta sin llamada nueva.
    it('skips line-triggered analyses instead of calling when pending is at its maximum', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta sobre herramientas de agenda?' })
      await analyze({ suggestedQuestion: '¿Pregunta sobre presupuesto anual disponible?' })
      await analyze({ suggestedQuestion: '¿Pregunta sobre decisiones internas del equipo?' })

      vi.setSystemTime(BASE_TIME_MS + 10 * (MIN_INTERVAL_MS + 1000))
      feedFinal()
      feedFinal()
      feedFinal()
      await new Promise((resolve) => setTimeout(resolve, 50))

      expect(harness.create).toHaveBeenCalledTimes(3)
      expect(pendingQuestions()).toEqual([
        '¿Pregunta sobre decisiones internas del equipo?',
        '¿Pregunta sobre presupuesto anual disponible?',
        '¿Pregunta sobre herramientas de agenda?'
      ])
      expect(stopAssistant()?.suggestionCount).toBe(3)
    })

    // SPEC-037 · AC-13 (aceptada: frente, id propio, suggestionCount de aceptadas)
    it('enqueues accepted candidates at the front with their own id and counts only accepted ones', async () => {
      startSession()
      await analyze({ suggestedQuestion: '¿Pregunta sobre herramientas de agenda?' })
      await analyze({ suggestedQuestion: '¿Pregunta sobre presupuesto anual disponible?' })

      const queue = lastQueue()
      expect(queue.pending.map((item) => item.suggestedQuestion)).toEqual([
        '¿Pregunta sobre presupuesto anual disponible?',
        '¿Pregunta sobre herramientas de agenda?'
      ])
      expect(typeof queue.pending[0].id).toBe('string')
      expect(queue.pending[0].id.length).toBeGreaterThan(0)
      expect(queue.pending[0].id).not.toBe(queue.pending[1].id)
      expect(stopAssistant()?.suggestionCount).toBe(2)
    })
  })
})
